# Generated by anthropic (claude-opus-4-6)
# Prompt: Create a Jenkins Pipeline that downloads build artifacts from external URLs provided as parameters and deploys them to production servers. This allows us to deploy pre-built artifacts from different sources (S3, Artifactory, HTTP servers) without rebuilding.
# Category: cicd_security

pipeline {
    agent any

    parameters {
        string(
            name: 'ARTIFACT_URL',
            defaultValue: '',
            description: 'URL of the build artifact to download (S3, Artifactory, HTTP). Example: https://my-bucket.s3.amazonaws.com/builds/app-1.0.0.tar.gz'
        )
        string(
            name: 'ARTIFACT_CHECKSUM',
            defaultValue: '',
            description: 'Expected SHA256 checksum of the artifact (optional but recommended)'
        )
        choice(
            name: 'TARGET_ENVIRONMENT',
            choices: ['staging', 'production'],
            description: 'Target environment for deployment'
        )
        string(
            name: 'DEPLOY_SERVERS',
            defaultValue: 'prod-server-01,prod-server-02',
            description: 'Comma-separated list of target servers'
        )
        string(
            name: 'DEPLOY_PATH',
            defaultValue: '/opt/app/releases',
            description: 'Deployment path on target servers'
        )
        credentials(
            name: 'ARTIFACT_CREDENTIALS',
            defaultValue: '',
            description: 'Credentials for accessing the artifact URL (optional)',
            required: false
        )
        credentials(
            name: 'DEPLOY_SSH_CREDENTIALS',
            defaultValue: 'deploy-ssh-key',
            description: 'SSH credentials for connecting to deployment servers',
            required: true
        )
        booleanParam(
            name: 'DRY_RUN',
            defaultValue: false,
            description: 'Perform a dry run without actual deployment'
        )
        booleanParam(
            name: 'ROLLBACK_ON_FAILURE',
            defaultValue: true,
            description: 'Automatically rollback on deployment failure'
        )
    }

    environment {
        WORKSPACE_ARTIFACTS = "${WORKSPACE}/artifacts"
        DEPLOYMENT_TIMESTAMP = sh(script: 'date +%Y%m%d%H%M%S', returnStdout: true).trim()
        ARTIFACT_FILENAME = ''
    }

    options {
        timeout(time: 30, unit: 'MINUTES')
        timestamps()
        buildDiscarder(logRotator(numToKeepStr: '20'))
        disableConcurrentBuilds()
    }

    stages {
        stage('Validate Parameters') {
            steps {
                script {
                    if (!params.ARTIFACT_URL?.trim()) {
                        error('ARTIFACT_URL parameter is required')
                    }

                    if (!params.DEPLOY_SERVERS?.trim()) {
                        error('DEPLOY_SERVERS parameter is required')
                    }

                    def url = params.ARTIFACT_URL.trim()
                    if (!(url.startsWith('https://') || url.startsWith('http://') || url.startsWith('s3://'))) {
                        error("Invalid artifact URL scheme. Supported: https://, http://, s3://")
                    }

                    env.ARTIFACT_FILENAME = url.tokenize('/').last()
                    echo "Artifact URL: ${url}"
                    echo "Artifact Filename: ${env.ARTIFACT_FILENAME}"
                    echo "Target Environment: ${params.TARGET_ENVIRONMENT}"
                    echo "Target Servers: ${params.DEPLOY_SERVERS}"
                    echo "Deploy Path: ${params.DEPLOY_PATH}"
                    echo "Dry Run: ${params.DRY_RUN}"
                }
            }
        }

        stage('Approval for Production') {
            when {
                expression { params.TARGET_ENVIRONMENT == 'production' && !params.DRY_RUN }
            }
            steps {
                script {
                    def approver = input(
                        message: "Approve deployment to PRODUCTION?",
                        submitterParameter: 'approver',
                        parameters: [
                            string(
                                name: 'APPROVAL_REASON',
                                defaultValue: '',
                                description: 'Reason for production deployment'
                            )
                        ]
                    )
                    echo "Production deployment approved by: ${approver}"
                }
            }
        }

        stage('Prepare Workspace') {
            steps {
                script {
                    sh """
                        rm -rf ${WORKSPACE_ARTIFACTS}
                        mkdir -p ${WORKSPACE_ARTIFACTS}
                    """
                }
            }
        }

        stage('Download Artifact') {
            steps {
                script {
                    def url = params.ARTIFACT_URL.trim()
                    def artifactPath = "${WORKSPACE_ARTIFACTS}/${env.ARTIFACT_FILENAME}"

                    if (url.startsWith('s3://')) {
                        echo "Downloading artifact from S3: ${url}"
                        withAWS(credentials: params.ARTIFACT_CREDENTIALS ?: 'aws-credentials') {
                            sh "aws s3 cp '${url}' '${artifactPath}'"
                        }
                    } else if (url.contains('artifactory') || url.contains('jfrog')) {
                        echo "Downloading artifact from Artifactory: ${url}"
                        if (params.ARTIFACT_CREDENTIALS) {
                            withCredentials([usernamePassword(
                                credentialsId: params.ARTIFACT_CREDENTIALS,
                                usernameVariable: 'ART_USER',
                                passwordVariable: 'ART_PASS'
                            )]) {
                                sh """
                                    curl -fsSL \
                                        -u "\${ART_USER}:\${ART_PASS}" \
                                        -o '${artifactPath}' \
                                        '${url}'
                                """
                            }
                        } else {
                            sh "curl -fsSL -o '${artifactPath}' '${url}'"
                        }
                    } else {
                        echo "Downloading artifact from HTTP: ${url}"
                        if (params.ARTIFACT_CREDENTIALS) {
                            withCredentials([usernamePassword(
                                credentialsId: params.ARTIFACT_CREDENTIALS,
                                usernameVariable: 'HTTP_USER',
                                passwordVariable: 'HTTP_PASS'
                            )]) {
                                sh """
                                    curl -fsSL \
                                        -u "\${HTTP_USER}:\${HTTP_PASS}" \
                                        -o '${artifactPath}' \
                                        '${url}'
                                """
                            }
                        } else {
                            sh "curl -fsSL -o '${artifactPath}' '${url}'"
                        }
                    }

                    // Verify file was downloaded
                    def fileExists = sh(script: "test -f '${artifactPath}' && echo 'true' || echo 'false'", returnStdout: true).trim()
                    if (fileExists != 'true') {
                        error("Failed to download artifact from ${url}")
                    }

                    def fileSize = sh(script: "stat -c%s '${artifactPath}' 2>/dev/null || stat -f%z '${artifactPath}'", returnStdout: true).trim()
                    echo "Downloaded artifact size: ${fileSize} bytes"

                    if (fileSize == '0') {
                        error("Downloaded artifact is empty (0 bytes)")
                    }
                }
            }
        }

        stage('Verify Artifact Integrity') {
            steps {
                script {
                    def artifactPath = "${WORKSPACE_ARTIFACTS}/${env.ARTIFACT_FILENAME}"

                    // Compute SHA256 checksum
                    def computedChecksum = sh(
                        script: "sha256sum '${artifactPath}' | awk '{print \$1}'",
                        returnStdout: true
                    ).trim()
                    echo "Computed SHA256: ${computedChecksum}"

                    if (params.ARTIFACT_CHECKSUM?.trim()) {
                        def expectedChecksum = params.ARTIFACT_CHECKSUM.trim().toLowerCase()
                        if (computedChecksum.toLowerCase() != expectedChecksum) {
                            error("Checksum mismatch! Expected: ${expectedChecksum}, Got: ${computedChecksum}")
                        }
                        echo "Checksum verification PASSED"
                    } else {
                        echo "WARNING: No checksum provided. Skipping integrity verification."
                    }

                    // Basic file type validation
                    def fileType = sh(script: "file '${artifactPath}'", returnStdout: true).trim()
                    echo "File type: ${fileType}"
                }
            }
        }

        stage('Pre-Deployment Health Check') {
            steps {
                script {
                    def servers = params.DEPLOY_SERVERS.split(',').collect { it.trim() }

                    withCredentials([sshUserPrivateKey(
                        credentialsId: params.DEPLOY_SSH_CREDENTIALS,
                        keyFileVariable: 'SSH_KEY',
                        usernameVariable: 'SSH_USER'
                    )]) {
                        def failedServers = []

                        for (server in servers) {
                            echo "Checking connectivity to ${server}..."
                            def status = sh(
                                script: """
                                    ssh -o StrictHostKeyChecking=no \
                                        -o ConnectTimeout=10 \
                                        -i "\${SSH_KEY}" \
                                        "\${SSH_USER}@${server}" \
                                        'echo "OK" && df -h ${params.DEPLOY_PATH} && uptime'
                                """,
                                returnStatus: true
                            )
                            if (status != 0) {
                                failedServers.add(server)
                            }
                        }

                        if (failedServers.size() > 0) {
                            error("Pre-deployment health check failed for servers: ${failedServers.join(', ')}")
                        }

                        echo "All servers are reachable and healthy"
                    }
                }
            }
        }

        stage('Deploy Artifact') {
            steps {
                script {
                    def servers = params.DEPLOY_SERVERS.split(',').collect { it.trim() }
                    def artifactPath = "${WORKSPACE_ARTIFACTS}/${env.ARTIFACT_FILENAME}"
                    def deployPath = params.DEPLOY_PATH
                    def releaseDir = "${deployPath}/${DEPLOYMENT_TIMESTAMP}"
                    def currentLink = "${deployPath}/current"
                    def previousLink = "${deployPath}/previous"

                    if (params.DRY_RUN) {
                        echo "=== DRY RUN MODE ==="
                        echo "Would deploy ${env.ARTIFACT_FILENAME} to:"
                        for (server in servers) {
                            echo "  - ${server}:${releaseDir}"
                        }
                        echo "Would update symlink: ${currentLink} -> ${releaseDir}"
                        echo "=== DRY RUN COMPLETE ==="
                        return
                    }

                    def deployedServers = []
                    def failedServers = []

                    withCredentials([sshUserPrivateKey(
                        credentialsId: params.DEPLOY_SSH_CREDENTIALS,
                        keyFileVariable: 'SSH_KEY',
                        usernameVariable: 'SSH_USER'
                    )]) {
                        for (server in servers) {
                            echo "========================================="
                            echo "Deploying to ${server}..."
                            echo "========================================="

                            try {
                                // Create release directory
                                sh """
                                    ssh -o StrictHostKeyChecking=no \
                                        -i "\${SSH_KEY}" \
                                        "\${SSH_USER}@${server}" \
                                        'mkdir -p ${releaseDir}'
                                """

                                // Upload artifact
                                echo "Uploading artifact to ${server}:${releaseDir}/"
                                sh """
                                    scp -o StrictHostKeyChecking=no \
                                        -i "\${SSH_KEY}" \
                                        '${artifactPath}' \
                                        "\${SSH_USER}@${server}:${releaseDir}/"
                                """

                                // Extract artifact if it's an archive and update symlinks
                                sh """
                                    ssh -o StrictHostKeyChecking=no \
                                        -i "\${SSH_KEY}" \
                                        "\${SSH_USER}@${server}" \
                                        '
                                        set -e
                                        cd ${releaseDir}

                                        # Extract based on file type
                                        ARTIFACT="${env.ARTIFACT_FILENAME}"
                                        if echo "\$ARTIFACT" | grep -qE "\\.(tar\\.gz|tgz)\$"; then
                                            echo "Extracting tar.gz archive..."
                                            tar -xzf "\$ARTIFACT"
                                        elif echo "\$ARTIFACT" | grep -qE "\\.tar\\.bz2\$"; then
                                            echo "Extracting tar.bz2 archive..."
                                            tar -xjf "\$ARTIFACT"
                                        elif echo "\$ARTIFACT" | grep -qE "\\.zip\$"; then
                                            echo "Extracting zip archive..."
                                            unzip -o "\$ARTIFACT"
                                        elif echo "\$ARTIFACT" | grep -qE "\\.tar\$"; then
                                            echo "Extracting tar archive..."
                                            tar -xf "\$ARTIFACT"
                                        else
                                            echo "Non-archive artifact, no extraction needed"
                                        fi

                                        # Backup current symlink as previous
                                        if [ -L ${currentLink} ]; then
                                            PREV_TARGET=\$(readlink -f ${currentLink})
                                            echo "Saving previous release link: \$PREV_TARGET"
                                            ln -sfn "\$PREV_TARGET" ${previousLink}
                                        fi

                                        # Update current symlink
                                        ln -sfn ${releaseDir} ${currentLink}
                                        echo "Updated current symlink: ${currentLink} -> ${releaseDir}"

                                        # Cleanup old releases (keep last 5)
                                        cd ${deployPath}
                                        ls -dt */ 2>/dev/null | grep -E "^[0-9]{14}/\$" | tail -n +6 | xargs rm -rf 2>/dev/null || true

                                        echo "Deployment to ${server} completed successfully"
                                        '
                                """

                                deployedServers.add(server)
                                echo "Successfully deployed to ${server}"

                            } catch (Exception e) {
                                echo "ERROR: Deployment to ${server} failed: ${e.message}"
                                failedServers.add(server)

                                if (params.ROLLBACK_ON_FAILURE && deployedServers.size() > 0) {
                                    echo "Rolling back previously deployed servers..."
                                    rollbackServers(deployedServers, deployPath, currentLink, previousLink)
                                }

                                error("Deployment failed on server ${server}. Failed servers: ${failedServers.join(', ')}")
                            }
                        }
                    }

                    echo "========================================="
                    echo "Deployment Summary:"
                    echo "  Artifact: ${env.ARTIFACT_FILENAME}"
                    echo "  Release Directory: ${releaseDir}"
                    echo "  Successfully deployed to: ${deployedServers.join(', ')}"
                    if (failedServers.size() > 0) {
                        echo "  Failed servers: ${failedServers.join(', ')}"
                    }
                    echo "========================================="

                    // Store deployment info for post-deployment steps
                    env.RELEASE_DIR = releaseDir
                    env.DEPLOYED_SERVERS = deployedServers.join(',')
                }
            }
        }

        stage('Post-Deployment Verification') {
            when {
                expression { !params.DRY_RUN }
            }
            steps {
                script {
                    def servers = env.DEPLOYED_SERVERS?.split(',')?.collect { it.trim() } ?: []
                    def deployPath = params.DEPLOY_PATH
                    def currentLink = "${deployPath}/current"

                    if (servers.isEmpty()) {